const allEquipment = $input.all();
const equipmentId = $('Edit Fields - รับข้อมูลยืม').first().json.equipmentId;

for (const item of allEquipment) {
  if (item.json['รหัสอุปกรณ์'] === equipmentId) {
    const remaining = Number(item.json['จำนวนคงเหลือ'] || 0);
    return [{
      json: {
        found: true,
        hasStock: remaining > 0,
        'รหัสอุปกรณ์': item.json['รหัสอุปกรณ์'],
        'ชื่ออุปกรณ์': item.json['ชื่ออุปกรณ์'],
        'จำนวนคงเหลือ': remaining,
        'จำนวนทั้งหมด': Number(item.json['จำนวนทั้งหมด'] || 0)
      }
    }];
  }
}
return [{ json: { found: false, hasStock: false } }];

const allRecords = $input.all();
const now = new Date();
const year = now.getFullYear();
const month = String(now.getMonth() + 1).padStart(2, '0');
const day = String(now.getDate()).padStart(2, '0');
let maxNum = 0;

for (const item of allRecords) {
  const id = item.json['รหัสยืม'] || '';
  const match = id.match(/^BR\d{4}-(\d{5})$/);
  if (match) {
    const num = parseInt(match[1]);
    if (num > maxNum) maxNum = num;
  }
}

const nextNum = maxNum + 1;
const borrowId = 'BR' + year + '-' + String(nextNum).padStart(5, '0');

return [{
  json: {
    borrowId: borrowId,
    borrowDate: year + '-' + month + '-' + day
  }
}];

const allItems = $input.all();
const borrowId = $('Edit Fields - รับรหัสยืม').first().json.borrowId;

for (const item of allItems) {
  if (item.json['รหัสยืม'] === borrowId && (item.json['สถานะ'] === 'ยืมอยู่' || item.json['สถานะ'] === 'เกินกำหนด')) {
    return [{
      json: {
        found: true,
        'รหัสยืม': item.json['รหัสยืม'],
        'ชื่อผู้ยืม': item.json['ชื่อผู้ยืม'],
        Email: item.json['Email'],
        'อุปกรณ์': item.json['อุปกรณ์'],
        'รหัสนศ.': item.json['รหัสนศ.'],
        'วันที่ยืม': item.json['วันที่ยืม'],
        'กำหนดคืน': item.json['กำหนดคืน'],
        'สถานะ': item.json['สถานะ']
      }
    }];
  }
}
return [{ json: { found: false } }];

const allItems = $input.all();
const today = new Date();
today.setHours(0, 0, 0, 0);

const overdueItems = [];

for (const item of allItems) {
  const status = item.json['สถานะ'];
  const dueDate = item.json['กำหนดคืน'];

  if (status !== 'ยืมอยู่' || !dueDate || dueDate === '-') continue;

  const due = new Date(dueDate);
  due.setHours(0, 0, 0, 0);

  if (due < today) {
    overdueItems.push(item);
  }
}

if (overdueItems.length === 0) {
  return [];
}

return overdueItems;
